#!/usr/bin/env python3
"""Validate persisted bowl-probe admission reports."""

from __future__ import annotations

import argparse
import json
from pathlib import Path


EXPECTED_PROFILES = {
    "dev-fast": Path(
        ".a0/runs/jit-dequant/real/qwen2.5-0.5b-instruct.dev-fast.bowl-probe.admission.json"
    ),
    "dev-balanced": Path(
        ".a0/runs/jit-dequant/real/qwen2.5-0.5b-instruct.dev-balanced.bowl-probe.admission.json"
    ),
    "dev-strict": Path(
        ".a0/runs/jit-dequant/real/qwen2.5-0.5b-instruct.dev-strict.bowl-probe.admission.json"
    ),
}

EXPECTED_ADMITTED = {
    "dev-fast": True,
    "dev-balanced": True,
    "dev-strict": False,
}

EXPECTED_CERTS = {
    "Gnosis.QualityMarginCacheAdmissibility",
    "Gnosis.EnergyMarginBridgeAdmissibility",
    "Gnosis.BasinSeparatrixAdmissibility",
    "Gnosis.JitDequantAdmissibility",
    "Gnosis.ConformalCoverageAdmissibility",
}


def validate_one(
    path: Path,
    expected_profile: str | None,
    require_gamma_frontier: bool,
    expected_admitted: bool | None = None,
) -> None:
    if not path.exists():
        raise SystemExit(f"missing admission report: {path}")

    payload = json.loads(path.read_text())
    if payload.get("tool") != "bowl-probe":
        raise SystemExit(f"{path}: tool must be bowl-probe")

    profile = payload.get("quality_profile")
    if expected_profile is not None and profile != expected_profile:
        raise SystemExit(f"{path}: expected profile {expected_profile}, got {profile}")

    admission = payload.get("admission")
    if not isinstance(admission, dict) or not isinstance(admission.get("admitted"), bool):
        raise SystemExit(f"{path}: admission.admitted must be boolean")
    if expected_admitted is not None and admission["admitted"] != expected_admitted:
        raise SystemExit(
            f"{path}: expected admission.admitted={expected_admitted}, "
            f"got {admission['admitted']}"
        )

    matrix = payload.get("matrix")
    if not isinstance(matrix, dict) or matrix.get("sample_rows", 0) <= 0:
        raise SystemExit(f"{path}: matrix.sample_rows must be positive")

    proof_modules = {
        item.get("module")
        for item in payload.get("proof_spine", [])
        if isinstance(item, dict)
    }
    missing = EXPECTED_CERTS - proof_modules
    if missing:
        raise SystemExit(f"{path}: missing proof modules: {sorted(missing)}")

    conformal = payload.get("conformal")
    rows = conformal.get("rows") if isinstance(conformal, dict) else None
    if not isinstance(rows, list) or not rows:
        raise SystemExit(f"{path}: conformal.rows must be non-empty")

    frontier = payload.get("gamma_frontier")
    if require_gamma_frontier and frontier is None:
        raise SystemExit(f"{path}: gamma_frontier is required")
    if frontier is not None:
        if not isinstance(frontier, dict):
            raise SystemExit(f"{path}: gamma_frontier must be an object or null")
        frontier_rows = frontier.get("rows")
        if not isinstance(frontier_rows, list) or not frontier_rows:
            raise SystemExit(f"{path}: gamma_frontier.rows must be non-empty")
        exact = frontier.get("exact_conformal_min_multiplier")
        if not isinstance(exact, (int, float)) or exact <= 0:
            raise SystemExit(
                f"{path}: gamma_frontier.exact_conformal_min_multiplier must be positive"
            )
        first = frontier.get("first_admitted_multiplier")
        if not isinstance(first, (int, float)) or first <= 0:
            raise SystemExit(
                f"{path}: gamma_frontier.first_admitted_multiplier must be positive"
            )

    print(f"OK {path} profile={profile} admitted={admission['admitted']}")


def main() -> None:
    parser = argparse.ArgumentParser()
    parser.add_argument(
        "--require-gamma-frontier",
        action="store_true",
        help="Require each report to include a non-empty gamma_frontier object.",
    )
    parser.add_argument(
        "paths",
        nargs="*",
        help="Optional explicit admission reports. Defaults to all dev profile reports.",
    )
    args = parser.parse_args()

    if args.paths:
        for raw in args.paths:
            validate_one(Path(raw), None, args.require_gamma_frontier)
    else:
        for profile, path in EXPECTED_PROFILES.items():
            validate_one(
                path,
                profile,
                args.require_gamma_frontier,
                EXPECTED_ADMITTED[profile],
            )


if __name__ == "__main__":
    main()
